WHERE s.SALES_YMD = #{salesYmd}

    AND s.SALES_EVENT_SEQ = #{salesEventSeq}

ORDER BY s.SALES_SEQ DESC




        AND s.SALES_YMD LIKE CONCAT(#{salesYear}, '%')


        AND s.SALES_EVENT_SEQ = #{salesEventSeq}


ORDER BY s.SALES_SEQ DESC


WHERE s.ITEM_CD = #{itemCd}
  AND s.SALES_YMD = #{salesYmd}
  AND (
    (#{salesEventSeq} IS NULL AND s.SALES_EVENT_SEQ IS NULL)
    OR s.SALES_EVENT_SEQ = #{salesEventSeq}
  )
LIMIT 1

